  function renderTeam(){return`<header class="page-head"><div><span class="eyebrow">PARTY PLANNER</span><h1>Team Builder</h1><p>Build a six-Pokémon party with natures, abilities, moves and adjusted stats.</p></div></header><section class="team-grid">${state.team.map(teamCard).join('')}</section>`}
  function bindTeam(root){root.querySelectorAll('[data-team-species]').forEach(x=>x.onchange=()=>{const i=Number(x.dataset.teamSpecies),id=Number(x.value)||null,old=state.team[i];if(!id){state.team[i]=blankTeamSlot();saveTeam();render();return}const p=pokemonById.get(id);state.team[i]={...blankTeamSlot(),pokemonId:id,nickname:old.nickname,nature:old.nature,ability:(p.abilities||[]).some(a=>a.name===old.ability)?old.ability:p.abilities?.[0]?.name||'',moves:old.moves};saveTeam();if(!state.caught.has(String(p.dexId))&&confirm(`${displayPokemonName(p)} is not marked as caught. Add it to your caught Pokédex?`)){state.caught.add(String(p.dexId));persist()}render()});root.querySelectorAll('[data-team-clear]').forEach(x=>x.onclick=()=>{state.team[Number(x.dataset.teamClear)]=blankTeamSlot();saveTeam();render()});root.querySelectorAll('[data-team-nickname]').forEach(x=>x.onchange=()=>{state.team[Number(x.dataset.teamNickname)].nickname=x.value.trim().slice(0,24);saveTeam();render()});root.querySelectorAll('[data-team-nature]').forEach(x=>x.onchange=()=>{state.team[Number(x.dataset.teamNature)].nature=x.value;saveTeam();render()});root.querySelectorAll('[data-team-ability]').forEach(x=>x.onchange=()=>{state.team[Number(x.dataset.teamAbility)].ability=x.value;saveTeam()});root.querySelectorAll('[data-team-move]').forEach(x=>x.onchange=()=>{const[i,m]=x.dataset.teamMove.split(':').map(Number);state.team[i].moves[m]=x.value;saveTeam()});root.querySelectorAll('[data-team-evolve]').forEach(x=>x.onclick=()=>{const[i,id]=x.dataset.teamEvolve.split(':').map(Number),current=state.team[i],target=pokemonById.get(id);if(!target)return;state.team[i]={...current,pokemonId:id,ability:(target.abilities||[]).some(a=>a.name===current.ability)?current.ability:target.abilities?.[0]?.name||'',moves:[...current.moves]};state.caught.add(String(target.dexId));localStorage.setItem('radical-red-caught',JSON.stringify([...state.caught]));saveTeam();updateProgress();render();toast(`${displayPokemonName(target)} evolved and was marked caught`)})}
  function saveFavorites(){localStorage.setItem(syncKeys.favorites,JSON.stringify(state.favorites));state.saveMeta.revision++;state.saveMeta.modifiedAt=new Date().toISOString();localStorage.setItem(syncKeys.meta,JSON.stringify(state.saveMeta));state.syncSnapshot=null;state.syncStatus=state.syncCode&&syncEndpoint?'local-newer':'unchecked'}
