  function renderFavorites(){return`<header class="page-head"><div><span class="eyebrow">BUILD LIBRARY</span><h1>Favorites</h1><p>Save complete Pokémon builds and move them in and out of your active team.</p></div><button class="primary" data-view="team">Open Team Builder</button></header><section class="favorites-grid">${state.favorites.length?state.favorites.map(favoriteCard).join(''):'<div class="favorites-empty"><img src="assets/items/heart-scale.png" alt=""><h2>No saved builds yet</h2><p>Open Team Builder and use Save build on any filled team card.</p><button class="primary" data-view="team">Build a team</button></div>'}</section>`}
  function bindFavorites(root){if(state.view==='team')root.querySelectorAll('.team-card').forEach((card,index)=>{if(!state.team[index]?.pokemonId)return;const button=document.createElement('button');button.className='team-save-build';button.dataset.teamSaveBuild=String(index);button.textContent='♥ Save build';card.querySelector('header')?.append(button)});root.querySelectorAll('[data-team-save-build]').forEach(x=>x.onclick=()=>{const slot=state.team[Number(x.dataset.teamSaveBuild)],p=pokemonById.get(Number(slot.pokemonId));if(!p)return;const label=prompt('Name this saved build:',slot.nickname||displayPokemonName(p));if(label===null)return;state.favorites.unshift({id:crypto.randomUUID(),label:String(label).trim().slice(0,36)||displayPokemonName(p),pokemonId:p.id,nickname:slot.nickname,nature:slot.nature,ability:slot.ability,moves:[...slot.moves],savedAt:new Date().toISOString()});saveFavorites();render();toast('Pokémon build saved to Favorites')});root.querySelectorAll('[data-favorite-delete]').forEach(x=>x.onclick=()=>{if(!confirm('Delete this saved build?'))return;state.favorites=state.favorites.filter(build=>build.id!==x.dataset.favoriteDelete);saveFavorites();render();toast('Saved build removed')});root.querySelectorAll('[data-favorite-add]').forEach(x=>x.onclick=()=>{const build=state.favorites.find(item=>item.id===x.dataset.favoriteAdd),target=root.querySelector(`[data-favorite-target="${x.dataset.favoriteAdd}"]`),index=Number(target?.value);if(!build||!Number.isInteger(index))return;if(state.team[index]?.pokemonId&&!confirm(`Replace the Pokémon currently in Slot ${index+1}?`))return;state.team[index]={...blankTeamSlot(),pokemonId:Number(build.pokemonId),nickname:build.nickname||'',nature:build.nature||'Hardy',ability:build.ability||'',moves:Array.from({length:4},(_,m)=>build.moves?.[m]||'')};saveTeam();navigate('team');toast('Saved build added to the team')})}
  const teamPokemonChoices=[...data.pokemon].sort((a,b)=>displayPokemonName(a).localeCompare(displayPokemonName(b)));
  function teamPokemonDatalist(){return`<datalist id="teamPokemonChoices">${teamPokemonChoices.map(p=>`<option value="${esc(displayPokemonName(p))}"></option>`).join('')}</datalist>`}
  function resolveTeamPokemon(value){const key=norm(value);return teamPokemonChoices.find(p=>norm(displayPokemonName(p))===key||norm(p.key)===key)||null}
