  function teamCard(slot,index){const p=pokemonById.get(Number(slot.pokemonId));if(!p)return`<article class="team-card empty-team"><header><span>SLOT ${index+1}</span><b>Empty</b></header><div class="team-empty-ball"><img src="assets/items/poke-ball.png" alt=""></div><label><span>Pokémon</span><input type="search" list="teamPokemonChoices" data-team-species-search="${index}" placeholder="Search Pokémon by name…" autocomplete="off"></label></article>`;const abilities=p.abilities||[],evolutions=(p.evolutions||[]).map(e=>({edge:e,target:pokemonById.get(Number(e.targetId))})).filter(x=>x.target);if(!abilities.some(a=>a.name===slot.ability))slot.ability=abilities[0]?.name||'';const ability=abilities.find(a=>a.name===slot.ability);return`<article class="team-card" style="--accent:${p.typeColours[0]||'var(--red)'}"><header><span>SLOT ${index+1}</span><button class="team-save-build" data-team-save-build="${index}">♥ Save build</button><button data-team-clear="${index}">Clear</button></header><div class="team-identity"><img src="${p.sprite}" alt=""><div><h2>${esc(slot.nickname||displayPokemonName(p))}</h2>${slot.nickname?`<small>${esc(displayPokemonName(p))}</small>`:''}${types(p)}<b>${p.bst} BST</b></div></div><label><span>Pokémon</span><input type="search" list="teamPokemonChoices" data-team-species-search="${index}" value="${esc(displayPokemonName(p))}" autocomplete="off"></label><div class="team-fields"><label><span>Nickname</span><input data-team-nickname="${index}" maxlength="24" value="${esc(slot.nickname)}" placeholder="${esc(p.name)}"></label><label><span>Nature</span><select data-team-nature="${index}">${natureSelectOptions(slot.nature)}</select></label><label><span>Ability</span><select data-team-ability="${index}">${abilities.map(a=>`<option value="${esc(a.name)}" ${slot.ability===a.name?'selected':''}>${esc(a.name)}</option>`).join('')}</select></label></div>${ability?`<article class="build-ability-info"><strong>${esc(ability.name)}</strong><p>${esc(ability.description||'No description available.')}</p></article>`:''}${statBars(p,slot.nature)}<div class="team-moves">${slot.moves.map((selected,m)=>`<label><span>Move ${m+1}</span>${learnableMoveSelect(p,selected,`data-team-move="${index}:${m}"`)}${miniMoveInfo(selected)}</label>`).join('')}</div>${evolutions.length?`<div class="team-evolutions team-evolutions--bottom"><span>EVOLUTION</span>${evolutions.map(({edge,target})=>`<button data-team-evolve="${index}:${target.id}">Evolve to ${esc(displayPokemonName(target))}<small>${esc(edge.method||'Evolution')}</small></button>`).join('')}</div>`:''}</article>`}
  function teamPhysicalCoverage(){const types=[...new Set(data.moves.map(move=>move.type))].sort(),coverage=new Map(types.map(type=>[type,[]]));state.team.forEach((slot,slotIndex)=>(slot.moves||[]).forEach(id=>{const move=moveById.get(Number(id));if(move&&move.category!=='Status'&&move.power)coverage.get(move.type)?.push({move,slotIndex})}));const covered=[...coverage.values()].filter(items=>items.length).length,totalMoves=[...coverage.values()].reduce((sum,items)=>sum+items.length,0);return`<section class="physical-coverage"><header><div><span class="eyebrow">OFFENSIVE COVERAGE</span><h2>Move-type overview</h2><p>Selected Physical and Special attacks across all six team slots. Status moves are excluded.</p></div><strong>${covered} / ${types.length} types · ${totalMoves} moves</strong></header><div>${types.map(type=>{const items=coverage.get(type),colour=data.moves.find(move=>move.type===type)?.typeColour||'var(--red)',details=items.map(item=>`${item.move.name} (${item.move.category}) · Slot ${item.slotIndex+1}`).join(', ');return`<article class="${items.length?'covered':'gap'}" style="--coverage-type:${colour}" title="${esc(details||`No selected damaging ${type}-type move`)}"><span>${esc(type)}</span><strong>${items.length||'—'}</strong><small>${items.length?'Covered':'Gap'}</small></article>`}).join('')}</div></section>`}
