  const badgeData=[['boulder','Boulder Badge','boulder_badge_by_jormxdos_dffpqjy-300w.png'],['cascade','Cascade Badge','cascade_badge_by_jormxdos_dffpqke-300w.png'],['thunder','Thunder Badge','thunder_badge_by_jormxdos_dffprjv-300w.png'],['rainbow','Rainbow Badge','rainbow_badge_by_jormxdos_dffprjy-300w.png'],['soul','Soul Badge','soul_badge_by_jormxdos_dffprkf-300w.png'],['marsh','Marsh Badge','marsh_badge_by_jormxdos_dffprkp-300w.png'],['volcano','Volcano Badge','volcano_badge_by_jormxdos_dffprkv-300w.png'],['earth','Earth Badge','earth_badge_by_jormxdos_dffprl8-300w.png']];
