  function renderHome(){const pct=Math.round(state.caught.size/Math.max(groups.length,1)*100);return`<header class="page-head overview-heading"><div><span class="eyebrow">RADICAL RED v4.1</span><h1>Field Guide</h1><p>Your current Pokédex, badge and party progress at a glance.</p></div></header><section class="overview-progress-row"><article class="overview-caught"><span class="eyebrow">POKÉDEX PROGRESS</span><div class="overview-progress-ring" style="--pct:${pct*3.6}deg"><div><strong>${pct}%</strong><span>${state.caught.size} / ${groups.length}</span></div></div><button class="secondary" data-view="pokedex">Continue catching</button></article><article class="overview-badges"><header><div><span class="eyebrow">GYM CHALLENGE</span><h2>Kanto Badges</h2></div><strong>${state.badges.size} / 8 obtained</strong></header><div>${badgeData.map(([id,name,file])=>`<button data-badge="${id}" class="${state.badges.has(id)?'obtained':''}" title="${state.badges.has(id)?'Mark as not obtained':'Mark as obtained'}"><span><img src="assets/badges/${file}" alt="${name}"></span><b>${name.replace(' Badge','')}</b><small>${state.badges.has(id)?'Obtained':'Not obtained'}</small></button>`).join('')}</div></article></section><section class="overview-team"><header><div><span class="eyebrow">CURRENT PARTY</span><h2>Your team</h2></div><button class="secondary" data-view="team">Edit team</button></header><div>${state.team.map((slot,i)=>{const p=pokemonById.get(Number(slot.pokemonId));return p?`<button data-view="team" class="filled"><span><img src="${p.sprite}" alt=""></span><strong>${esc(slot.nickname||displayPokemonName(p))}</strong><small>${slot.nickname?esc(displayPokemonName(p)):`Slot ${i+1}`}</small>${types(p)}</button>`:`<button data-view="team" class="empty"><span><img src="assets/items/poke-ball.png" alt=""></span><strong>Empty slot</strong><small>Slot ${i+1}</small></button>`}).join('')}</div></section>`}
  function celebrate(origin=document.body){if(matchMedia('(prefers-reduced-motion: reduce)').matches)return;const inDialog=dialog.contains(origin),host=inDialog?(dialog.querySelector('.celebration-layer')||dialog.appendChild(Object.assign(document.createElement('div'),{className:'celebration-layer'}))):document.body,rect=origin.getBoundingClientRect?.()||{left:innerWidth/2,top:innerHeight/2,width:0,height:0},colours=['#f13f57','#ffcf4a','#60d394','#64a8ff','#d779ff','#fff'];for(let i=0;i<34;i++){const bit=document.createElement('i');bit.className='celebration-bit';bit.style.cssText=`--x:${rect.left+rect.width/2}px;--y:${rect.top+rect.height/2}px;--dx:${(Math.random()-.5)*360}px;--dy:${-70-Math.random()*260}px;--r:${Math.random()*720-360}deg;--c:${colours[i%colours.length]};--delay:${Math.random()*.12}s`;host.append(bit);bit.addEventListener('animationend',()=>{bit.remove();if(inDialog&&!host.children.length)host.remove()})}}
  function bindOverview(root){root.querySelectorAll('[data-badge]').forEach(button=>button.onclick=()=>{const id=button.dataset.badge,obtaining=!state.badges.has(id);state.badges.has(id)?state.badges.delete(id):state.badges.add(id);if(obtaining)celebrate(button);saveBadges();render();toast(state.badges.has(id)?'Badge marked as obtained':'Badge marked as not obtained')})}
  const typeChart={Normal:[[],['Rock','Steel'],['Ghost']],Fire:[['Grass','Ice','Bug','Steel'],['Fire','Water','Rock','Dragon'],[]],Water:[['Fire','Ground','Rock'],['Water','Grass','Dragon'],[]],Electric:[['Water','Flying'],['Electric','Grass','Dragon'],['Ground']],Grass:[['Water','Ground','Rock'],['Fire','Grass','Poison','Flying','Bug','Dragon','Steel'],[]],Ice:[['Grass','Ground','Flying','Dragon'],['Fire','Water','Ice','Steel'],[]],Fighting:[['Normal','Ice','Rock','Dark','Steel'],['Poison','Flying','Psychic','Bug','Fairy'],['Ghost']],Poison:[['Grass','Fairy'],['Poison','Ground','Rock','Ghost'],['Steel']],Ground:[['Fire','Electric','Poison','Rock','Steel'],['Grass','Bug'],['Flying']],Flying:[['Grass','Fighting','Bug'],['Electric','Rock','Steel'],[]],Psychic:[['Fighting','Poison'],['Psychic','Steel'],['Dark']],Bug:[['Grass','Psychic','Dark'],['Fire','Fighting','Poison','Flying','Ghost','Steel','Fairy'],[]],Rock:[['Fire','Ice','Flying','Bug'],['Fighting','Ground','Steel'],[]],Ghost:[['Psychic','Ghost'],['Dark'],['Normal']],Dragon:[['Dragon'],['Steel'],['Fairy']],Dark:[['Psychic','Ghost'],['Fighting','Dark','Fairy'],[]],Steel:[['Ice','Rock','Fairy'],['Fire','Water','Electric','Steel'],[]],Fairy:[['Fighting','Dragon','Dark'],['Fire','Poison','Steel'],[]]};
  function typeEffectiveness(type,defenderTypes){const chart=typeChart[type]||[[],[],[]];return defenderTypes.reduce((value,def)=>value*(chart[2].includes(def)?0:chart[0].includes(def)?2:chart[1].includes(def)?.5:1),1)}
  function battleDamage(move,attacker,defender,attackerStats=attacker.stats,defenderStats=defender.stats){if(!move||move.category==='Status'||!move.power)return 0;const physical=move.category==='Physical',attack=attackerStats[physical?1:4]||1,defense=defenderStats[physical?2:5]||1,stab=attacker.types.includes(move.type)?1.5:1,accuracy=(move.accuracy??100)/100;return move.power*accuracy*(attack/Math.max(defense,1))*stab*typeEffectiveness(move.type,defender.types)}
  function boundedBattleScore(value){return Math.max(0,Math.min(100,Math.round(100*(1-Math.exp(-Math.max(0,value)/160)))))}
  function persistBattle(){localStorage.setItem('radical-red-battle-planner-v1',JSON.stringify(state.battle))}
  function enemyMoves(slot,p){return(slot.moves||[]).map(id=>moveById.get(Number(id))).filter(Boolean)}
  function recommendationFor(slot,index,enemies){const p=pokemonById.get(Number(slot.pokemonId)),stats=p?natureStats(p,slot.nature).stats:null;if(!p)return null;const selected=(slot.moves||[]).map(id=>moveById.get(Number(id))).filter(move=>move&&move.category!=='Status'&&move.power),fallback=selected.length?selected:teamMoves(p).filter(move=>move.category!=='Status'&&move.power);let offenseTotal=0,offenseMin=Infinity,bestMove=null,bestTarget=null,bestValue=0,threatMax=0,threatMove=null,threatSource=null,threatFallback=false;enemies.forEach(enemy=>{let enemyBest=0,enemyBestMove=null;fallback.forEach(move=>{const value=battleDamage(move,p,enemy,stats,enemy.stats);if(value>enemyBest){enemyBest=value;enemyBestMove=move}});offenseTotal+=enemyBest;offenseMin=Math.min(offenseMin,enemyBest);if(enemyBest>bestValue){bestValue=enemyBest;bestMove=enemyBestMove;bestTarget=enemy}const battleSlot=state.battle.find(item=>Number(item.pokemonId)===enemy.id),chosen=enemyMoves(battleSlot||{},enemy),potential=chosen.length?chosen:teamMoves(enemy).filter(move=>move.category!=='Status'&&move.power);potential.forEach(move=>{const value=battleDamage(move,enemy,p,enemy.stats,stats);if(value>threatMax){threatMax=value;threatMove=move;threatSource=enemy;threatFallback=!chosen.length}})});const average=offenseTotal/enemies.length,offenseMetric=average+(offenseMin===Infinity?0:offenseMin*.35),offenseScore=boundedBattleScore(bestValue),threatScore=boundedBattleScore(threatMax),rating=Math.round(boundedBattleScore(offenseMetric)*.7+(100-threatScore)*.3);return{slot,index,p,stats,rating,offenseScore,threatScore,bestMove,bestTarget,bestValue,threatMove,threatSource,threatFallback,threatMax,usedFallback:!selected.length}}
  function battleRecommendations(){const enemies=state.battle.map(slot=>pokemonById.get(Number(slot.pokemonId))).filter(Boolean);if(!enemies.length)return[];return state.team.map((slot,index)=>recommendationFor(slot,index,enemies)).filter(Boolean).sort((a,b)=>b.rating-a.rating)}
  function enemyBattleCard(slot,index){const p=pokemonById.get(Number(slot.pokemonId));if(!p)return`<article class="battle-enemy empty-team"><header><span>OPPONENT ${index+1}</span><b>Optional</b></header><div class="battle-empty"><img src="assets/items/vs-seeker.png" alt=""></div><label><span>Enemy Pokémon</span><input type="search" list="teamPokemonChoices" data-battle-species="${index}" placeholder="Search Pokémon by name…"></label></article>`;return`<article class="battle-enemy" style="--accent:${p.typeColours[0]||'var(--red)'}"><header><span>OPPONENT ${index+1}</span><button data-battle-remove="${index}">Remove</button></header><div class="battle-enemy-identity"><img src="${p.sprite}" alt=""><div><h2>${esc(displayPokemonName(p))}</h2>${types(p)}<b>${p.bst} BST</b></div></div><label><span>Enemy Pokémon</span><input type="search" list="teamPokemonChoices" data-battle-species="${index}" value="${esc(displayPokemonName(p))}"></label><div class="battle-enemy-moves">${slot.moves.map((selected,m)=>`<label><span>Known move ${m+1}</span>${learnableMoveSelect(p,selected,`data-battle-move="${index}:${m}"`)}${miniMoveInfo(selected)}</label>`).join('')}</div></article>`}
  function matchupLabel(multiplier){return multiplier===0?'Immune · ×0':multiplier<1?`Resisted · ×${multiplier}`:multiplier===1?'Neutral · ×1':multiplier>=4?'Double weakness · ×4':`Super effective · ×${multiplier}`}
  function recommendationCard(rec,rank){const label=rec.rating>=85?'Excellent matchup':rec.rating>=70?'Strong matchup':rec.rating>=50?'Fair matchup':'Risky matchup',move=rec.bestMove,offenceMultiplier=move&&rec.bestTarget?typeEffectiveness(move.type,rec.bestTarget.types):1,threatMultiplier=rec.threatMove?typeEffectiveness(rec.threatMove.type,rec.p.types):1;return`<article class="battle-recommendation ${rank===0?'best':''}"><header><span>#${rank+1} · ${rank===0?'Best team option':label}</span><strong>${rec.rating}<small>/100</small></strong></header><div><img src="${rec.p.sprite}" alt=""><div><h3>${esc(rec.slot.nickname||displayPokemonName(rec.p))}</h3><small>${rec.slot.nickname?esc(displayPokemonName(rec.p)):`Team slot ${rec.index+1}`}</small>${types(rec.p)}</div></div>${move?`<section class="recommendation-offence" style="--move-type:${move.typeColour}"><header><div><span class="eyebrow">BEST OFFENCE</span><h4>${esc(move.name)}</h4></div><strong>${rec.offenseScore}<small>/100 effectiveness</small></strong></header><div class="recommendation-move-tags">${moveTypePill(move)}<span class="move-category ${move.category.toLowerCase()}">${esc(move.category)}</span><span class="matchup-tag ${offenceMultiplier>1?'effective':offenceMultiplier<1?'resisted':''}">${matchupLabel(offenceMultiplier)}</span>${rec.usedFallback?'<span class="fallback-tag">Learnset fallback</span>':'<span class="selected-tag">Team move</span>'}</div><dl><div><dt>Power</dt><dd>${move.power??'—'}</dd></div><div><dt>Accuracy</dt><dd>${move.accuracy?move.accuracy+'%':'—'}</dd></div><div><dt>Threat taken</dt><dd>${rec.threatScore}/100</dd></div></dl><p>${esc(move.description||'No description available.')}</p></section>`:'<section class="recommendation-offence"><p>No damaging move could be identified.</p></section>'}<div class="recommendation-threat"><strong>Largest expected threat</strong><span>${rec.threatMove?`${esc(rec.threatMove.name)} · ${rec.threatMove.type} · ${matchupLabel(threatMultiplier)} · ${rec.threatScore}/100${rec.threatFallback?' · Learnset estimate':''}`:'No damaging threat identified'}</span></div><p class="recommendation-method">${rec.usedFallback?'No damaging move is selected for this build, so this suggestion uses its strongest level-up, TM/HM or tutor option.':'This score uses the moves currently selected in Team Builder.'} ${rec.threatFallback?'No enemy move was selected, so the threat uses that opponent’s strongest documented damaging move.':''}</p><button data-view="team">Edit build</button></article>`}
  function renderBattle(){const recommendations=battleRecommendations(),hasEnemies=state.battle.some(slot=>slot.pokemonId);return`<header class="page-head"><div><span class="eyebrow">MATCHUP LAB</span><h1>Battle Planner</h1><p>Select up to two opponents and optionally identify their moves.</p></div><button class="secondary" data-battle-clear ${hasEnemies?'':'disabled'}>Clear planner</button></header>${teamPokemonDatalist()}<section class="battle-enemies">${state.battle.map(enemyBattleCard).join('')}</section><section class="battle-results"><header><div><span class="eyebrow">TEAM RECOMMENDATIONS</span><h2>Who should you use?</h2></div><p>Type matchups, move power, category, stats and known enemy attacks are included.</p></header>${!hasEnemies?'<div class="battle-placeholder">Choose at least one enemy Pokémon to calculate recommendations.</div>':!recommendations.length?'<div class="battle-placeholder">Add Pokémon to Team Builder before calculating this matchup.</div>':`<div>${recommendations.map(recommendationCard).join('')}</div>`}</section>`}
