  function addBattleFromPokedex(id){const p=pokemonById.get(Number(id));if(!p)return;const already=state.battle.some(slot=>slot.pokemonId);if(already&&!state.battle.some(slot=>Number(slot.pokemonId)===p.id)){if(!confirm('The Battle Planner already contains Pokémon. Clear it and start a fresh matchup?'))return;clearBattle()}if(!state.battle.some(slot=>Number(slot.pokemonId)===p.id)){state.battle[0]={pokemonId:p.id,moves:['','','','']};persistBattle()}dialog.close();navigate('battle')}
