  function eggPokemon(name){const alias=eggFormAliases[norm(name)];return typeof alias==='number'?pokemonById.get(alias):formByName.get(norm(alias||name))}
  function eggPool(source,query=''){const q=norm(query),sourceMatch=q&&(norm(source.title).includes(q)||norm(source.category).includes(q)||norm(source.location).includes(q)||norm(source.method).includes(q));return source.pokemon.map(name=>({name,pokemon:eggPokemon(name)})).filter(entry=>entry.pokemon&&(!q||sourceMatch||norm(entry.name).includes(q)||norm(displayPokemonName(entry.pokemon)).includes(q)))}
  function eggPokemonCard(entry){const p=entry.pokemon,caught=state.caught.has(String(p.dexId)),rank=bstRank(p.bst);return`<article class="egg-pokemon" style="--accent:${p.typeColours[0]}"><button class="egg-pokemon-info" data-pokemon="${p.id}"><img src="${p.sprite}" alt=""><span><strong>${esc(displayPokemonName(p))}</strong>${types(p)}<small>${p.bst} BST · ${rank} Rank</small></span></button><button class="caught-ball ${caught?'caught':''}" data-caught="${p.dexId}" aria-label="${caught?'Caught':'Mark as caught'}"><img src="assets/ui/pokeball.svg" alt=""></button></article>`}
  function eggSourceCard(source){const pool=eggPool(source,state.eggQuery),open=state.eggExpandAll||state.eggQuery||state.eggFilter;return`<details class="egg-source-card" ${open?'open':''} data-egg-source-card="${esc(source.id)}"><summary><span><img src="assets/items/pokemon-egg.png" alt=""><span><b>${esc(source.title)}</b><small>${esc(source.location)} · ${esc(source.cost)}</small></span></span><span><i>${pool.length} possible hatches</i><b>⌄</b></span></summary><div class="egg-source-body"><section class="egg-source-info"><span class="eyebrow">${esc(source.category)}</span><h2>${esc(source.title)}</h2><dl><div><dt>Location</dt><dd>${esc(source.location)}</dd></div><div><dt>Cost</dt><dd>${esc(source.cost)}</dd></div><div><dt>Unlock</dt><dd>${esc(source.unlock)}</dd></div></dl><p>${esc(source.method)}</p>${source.note?`<p class="egg-note">${esc(source.note)}</p>`:''}</section><section class="egg-pool"><header><div><span class="eyebrow">HATCH POOL</span><h3>${pool.length} Pokémon</h3></div></header><div>${pool.map(eggPokemonCard).join('')||'<p class="empty">No Pokémon in this egg pool match the search.</p>'}</div></section></div></details>`}
  function renderEggs(embedded=false){const q=norm(state.eggQuery),sources=eggData.filter(source=>(!state.eggFilter||source.id===state.eggFilter)&&(!q||norm(source.title).includes(q)||norm(source.category).includes(q)||norm(source.location).includes(q)||norm(source.method).includes(q)||eggPool(source,state.eggQuery).length));const hatchCount=sources.reduce((sum,source)=>sum+eggPool(source,state.eggQuery).length,0);return`${embedded?`<div class="location-subsection-heading"><span class="eyebrow">HATCHERY GUIDE</span><h2>Eggs</h2><p>${sources.length} egg sources · ${hatchCount} possible hatch entries shown</p></div>`:`<header class="page-head"><div><span class="eyebrow">HATCHERY GUIDE</span><h1>Eggs</h1><p>${sources.length} egg sources · ${hatchCount} possible hatch entries shown</p></div></header>`}<section class="legendary-controls egg-controls"><div><input id="eggSearch" type="search" placeholder="Search egg sources, locations or Pokémon…" value="${esc(state.eggQuery)}"><button data-egg-expand>${state.eggExpandAll?'Collapse all':'Expand all'}</button></div><nav><button data-egg-filter="" class="${!state.eggFilter?'active':''}">All</button>${eggData.map(source=>`<button data-egg-filter="${esc(source.id)}" class="${state.eggFilter===source.id?'active':''}">${esc(source.title)}</button>`).join('')}</nav></section><section class="legendary-list egg-source-list">${sources.map(eggSourceCard).join('')||'<p class="empty">No egg sources or hatchable Pokémon match those filters.</p>'}</section><p class="legendary-source">Wonder, Paldean and Seviian pools are documented in the <a href="https://www.scribd.com/document/849059328/Wonder-Egg-Pokemon-Pools-v4-1-Radical-Red" target="_blank" rel="noopener">Radical Red v4.1 Wonder Egg Pools ↗</a>.</p>`}
  function bindEggs(root){const search=root.querySelector('#eggSearch');if(search)search.oninput=e=>{state.eggQuery=e.target.value;state.eggFilter='';render();focusEnd('#eggSearch')};root.querySelectorAll('[data-egg-filter]').forEach(button=>button.onclick=()=>{state.eggFilter=button.dataset.eggFilter;state.eggQuery='';render()});const expand=root.querySelector('[data-egg-expand]');if(expand)expand.onclick=()=>{state.eggExpandAll=!state.eggExpandAll;render()}}
  function evolutionSection(title, entries){ return `<div class="evolution-group"><h4>${title}</h4>${entries.length?`<div class="evolution-list">${entries.map(entry=>`<button data-evo-pokemon="${entry.pokemon.id}"><img src="${entry.pokemon.sprite}" alt=""><span><strong>${esc(displayPokemonName(entry.pokemon))}</strong><small><b class="evolution-bst">${bstRank(entry.pokemon.bst)} Rank · ${entry.pokemon.bst} BST</b> · ${esc(entry.method)}</small></span><b>→</b></button>`).join('')}</div>`:'<p>No documented evolutions.</p>'}</div>`; }
  function locationSection(entries,p){ return `<section class="pokemon-locations"><h3>Locations</h3>${entries.length?`<div class="pokemon-location-list">${entries.map(entry=>entry.egg?`<button data-egg-source="${esc(entry.sourceId)}" class="egg-location-entry"><span><strong>${esc(entry.location)}</strong><small>${esc(entry.category)} · ${esc(entry.method)} · ${esc(entry.cost)}</small></span><b>→</b></button>`:entry.acquisition?`<button data-acquisition-section="${esc(entry.section)}" data-acquisition-query="${esc(['special','unobtainable'].includes(entry.section)?entry.query:entry.location)}" class="acquisition-location-entry"><span><strong>${esc(entry.location)}</strong><small>${entry.period==='day'?'☀ Day · ':entry.period==='night'?'☾ Night · ':''}${esc(entry.category)}${entry.level?` · Lv. ${esc(entry.level)}`:''}${entry.rarity!=null?` · ${entry.rarity}%`:''}${entry.method?` · ${esc(entry.method)}`:''}${entry.cost?` · ${esc(entry.cost)}`:''}</small></span><b>→</b></button>`:entry.legendary?`<${entry.linked?'button':'article'} ${entry.linked?`data-pokemon-location="${esc(entry.location)}" data-location-period="day"`:''} class="legendary-location-entry"><span><strong>${esc(entry.location)}</strong><small>${esc(entry.category)} · ${esc(entry.method)}${entry.code?` · Code: ${esc(entry.code)}`:''}</small></span><b>${entry.linked?'→':'Guide'}</b></${entry.linked?'button':'article'}>`:`<button data-pokemon-location="${esc(entry.location)}" data-location-period="${entry.period}"><span><strong>${esc(entry.location)}</strong><small>${entry.period==='day'?'☀ Day':'☾ Night'} · ${entry.level?'Lv. '+esc(entry.level):'Level varies'}</small></span><b>${entry.rarity==null?'—':entry.rarity+'%'}</b></button>`).join('')}</div>`:'<p>No direct encounter or acquisition location is documented for this form.</p>'}${evolutionRouteSection(p)}</section>`; }
  function openPokemon(id){ const p=pokemonById.get(Number(id)); if(!p)return; const key=String(p.dexId), caught=state.caught.has(key), labels=['HP','Attack','Defense','Speed','Sp. Atk','Sp. Def'], from=evolutionLinks(p,'from'), to=evolutionLinks(p,'to'), locations=pokemonLocations(p), group=groups.find(item=>item.dexId===key); dialog.querySelector('#dialogContent').innerHTML=`<div class="dialog-actions"><button class="caught-ball detail-caught ${caught?'caught':''}" data-caught="${key}" title="${caught?'Mark not caught':'Mark caught'}" aria-label="${caught?'Caught':'Not caught'}"><img src="assets/ui/pokeball.svg" alt=""></button><button class="dialog-close" aria-label="Close">×</button></div><div class="detail-hero" style="--accent:${p.typeColours[0]}"><img src="${p.sprite}" alt=""><div><span class="eyebrow">#${String(p.dexId).padStart(4,'0')}</span><h2>${esc(displayPokemonName(p))}</h2>${types(p)}<strong>${p.bst} BST</strong>${group&&group.forms.length>1?`<div class="detail-form-row" data-current-id="${p.id}"><button data-detail-step="-1" data-detail-group="${key}" aria-label="Previous form">‹</button><span>${esc(formName(group,p))}</span><button data-detail-step="1" data-detail-group="${key}" aria-label="Next form">›</button></div>`:''}</div></div><section class="stats">${p.stats.map((v,i)=>`<div><span>${labels[i]}</span><b>${v}</b><i><em style="width:${Math.min(100,v/1.55)}%"></em></i></div>`).join('')}</section><section class="abilities"><h3>Abilities</h3>${p.abilities.map(a=>`<article><b>${esc(a.name)}</b><p>${esc(a.description||'No description available.')}</p></article>`).join('')}</section>${pokemonMovesSection(p)}<section class="evolutions"><h3>Evolution family</h3>${evolutionSection('Evolves from',from)}${evolutionSection('Evolves to',to)}</section>${locationSection(locations,p)}`; dialog.showModal(); dialog.querySelector('.dialog-close').onclick=()=>dialog.close(); bind(dialog); }
  function goToPokemon(id){ const p=pokemonById.get(Number(id)); if(!p)return; dialog.close(); state.query=p.name; state.type='all'; state.dexCaughtFilter='all'; state.selected[String(p.dexId)]=p.id; navigate('pokedex'); requestAnimationFrame(()=>document.querySelector(`[data-species="${p.dexId}"]`)?.scrollIntoView({behavior:'smooth',block:'center'})); }
  function goToLocation(name,period){ dialog.close(); state.locationSection='wild';state.query=''; state.locationFilter=name; state.period=period; navigate('locations'); requestAnimationFrame(()=>document.querySelector(`[data-location="${norm(name)}"]`)?.scrollIntoView({behavior:'smooth',block:'center'})); }
